        private bool UserAccOn = true;
        string ImgNon = "";
        string ImgLink;
        string ImgLinkEvents;
        private int IdUsers;
        int id;
        public Moderator(int Id)
        {
            InitializeComponent();
            LoadCard();
            UpdateButtonsVisibility();

            int hour = DateTime.Now.Hour;

            if (hour >= 5 && hour < 12)
                DateWelcome.Content = "Доброе утро";
            else if (hour >= 12 && hour < 18)
                DateWelcome.Content = "Добрый день";
            else if (hour >= 18 && hour < 23)
                DateWelcome.Content = "Добрый вечер";
            else
                DateWelcome.Content = "Доброй ночи";

            id = Id;

            using (VBZ_2Entities1 context = new VBZ_2Entities1())
            {
                var user = context.User.FirstOrDefault(x => x.Id == Id);
                IdUsers = user.Id;

                name_TXT.Text = user.Name;
                lust_Name_TXT.Text = user.Surname;
                sec_Name_TXT.Text = user.Patronymic;
                mail_TXT.Text = user.Mail;
                phone_TXT.Text = user.Phone.ToString();
                password_TXT.Password = user.Password;
                password_Acsess_TXT.Password = user.Password;
                ImgLink = user.Photos;
                Dates.Text = user.DateofBirth.ToString();
                Role_TXT.Text = user.RoleName;
                Gender_TXT.Text = user.Gender;

                TitleName.Content = $"Модератор - {user.Surname} {user.Name}";


                try
                {
                    byte[] imageBytes = Convert.FromBase64String(user.Photos);
                    using (MemoryStream ms = new MemoryStream(imageBytes))
                    {
                        BitmapImage bitmap = new BitmapImage();
                        bitmap.BeginInit();
                        bitmap.CacheOption = BitmapCacheOption.OnLoad;
                        bitmap.StreamSource = ms;
                        bitmap.EndInit();
                        bitmap.Freeze();
                        icon_User_IMG.Source = bitmap;
                    }
                }
                catch
                {
                    byte[] imageBytes = Convert.FromBase64String(ImgNon);
                    using (MemoryStream ms = new MemoryStream(imageBytes))
                    {
                        BitmapImage bitmap = new BitmapImage();
                        bitmap.BeginInit();
                        bitmap.CacheOption = BitmapCacheOption.OnLoad;
                        bitmap.StreamSource = ms;
                        bitmap.EndInit();
                        bitmap.Freeze();
                        icon_User_IMG.Source = bitmap;
                    }
                }
            }
        }

        private void SubscribeBTNS_Click(object sender, RoutedEventArgs e)
        {
            Button button = sender as Button;
            if (button != null)
            {
                int id = (int)button.Tag;
                using (VBZ_2Entities1 context = new VBZ_2Entities1())
                {
                    var selectedItemId = context.SecurityEvents.FirstOrDefault(x => x.Id == id);
                    if (!UserAccOn)
                    {
                        Messages(PackIconKind.Warning,
                                 "Предупрежение",
                                 "Записаться можно только зарегистрированным пользователям, если вы не зарегистрированы, то зарегистрируйтесь, или войдите в аккаунт",
                                 "Предупрежение");
                    }
                    else
                    {
                        var existingSubscription = context.SetEvents
                            .FirstOrDefault(x => x.UserId == IdUsers && x.SecEventsId == id);

                        if (existingSubscription == null)
                        {
                            SetEvents setEvents = new SetEvents();
                            setEvents.UserId = IdUsers;
                            setEvents.SecEventsId = id;
                            setEvents.Activity = 1;

                            context.SetEvents.Add(setEvents);
                            context.SaveChanges();

                            Messages(PackIconKind.Check,
                                     "Успех",
                                     "Вы успешно записались на мероприятие",
                                     "Успех");

                            LoadCard();
                        }
                        else
                        {
                            Messages(PackIconKind.Info,
                                     "Информация",
                                     "Вы уже подписаны на это мероприятие",
                                     "Информация");
                        }
                    }
                }
            }
        }

