            using (VBZ_2Entities1 context = new VBZ_2Entities1())
            {
                try
                {
                    var UserEdits = context.User.FirstOrDefault(x => x.Id == id);

                    UserEdits.Name = name_TXT.Text;
                    UserEdits.Surname = lust_Name_TXT.Text;
                    UserEdits.Patronymic = sec_Name_TXT.Text;
                    UserEdits.Mail = mail_TXT.Text;
                    UserEdits.DateofBirth = DateTime.Parse(Dates.Text);
                    UserEdits.Password = password_TXT.Password;
                    UserEdits.Gender = Gender_TXT.Text;
                    UserEdits.RoleName = Role_TXT.Text;
                    UserEdits.Photos = ImgLink;

                    context.SaveChanges();

                    save_User_BTN.IsEnabled = false;
                    name_TXT.IsEnabled = false;
                    lust_Name_TXT.IsEnabled = false;
                    sec_Name_TXT.IsEnabled = false;
                    mail_TXT.IsEnabled = false;
                    phone_TXT.IsEnabled = false;
                    password_TXT.IsEnabled = false;
                    password_Acsess_TXT.IsEnabled = false;
                    Dates.IsEnabled = false;
                    edit_User_BTN.IsEnabled = true;
                    edit_Photo_User_BTN.Visibility = Visibility.Collapsed;
                }
                catch (Exception ex)
